  buildMessage msg =
    (if msg.priorityPriorityKey == 0 then mempty else archVarint 8 (fromIntegral msg.priorityPriorityKey))
    <> (if msg.priorityFairnessKey == T.empty then mempty else archString 18 msg.priorityFairnessKey)
    <> (if msg.priorityFairnessWeight == 0 then mempty else archFloat 29 msg.priorityFairnessWeight)
    <> encodeUnknownFields msg.priorityUnknownFields

